<template>
    <div class="decrypt-container">
        <div class="header">
            <h1>{{ msg }}</h1>
        </div>
        
        <div class="content two-column">
            <div class="decrypt-panel">
                <h2>参数解密</h2>
                <div class="input-section">
                    <label for="app-ciphertext">密文：</label>
                    <textarea
                        id="app-ciphertext"
                        v-model="appCiphertext"
                        placeholder="请输入 APP 参数密文..."
                        class="textarea-input"
                        rows="14"
                    ></textarea>
                </div>

                <div class="button-section">
                    <button
                        @click="handleAppDecrypt"
                        :disabled="!appCiphertext.trim() || isAppDecrypting"
                        class="decrypt-btn"
                    >
                        {{ isAppDecrypting ? '解密中...' : '解密' }}
                    </button>
                    <button
                        @click="handleAppClear"
                        class="clear-btn"
                    >
                        清空
                    </button>
                </div>

                <div class="output-section">
                    <label for="app-plaintext">明文：</label>
                    <textarea
                        id="app-plaintext"
                        v-model="appPlaintext"
                        placeholder="解密后的明文将显示在这里..."
                        class="textarea-output"
                        rows="14"
                        readonly
                    ></textarea>
                </div>

                <div v-if="appErrorMessage" class="error-message">
                    {{ appErrorMessage }}
                </div>
            </div>

            <div class="decrypt-panel">
                <h2>非 APP 参数解密</h2>
                <div class="input-section">
                    <label for="normal-ciphertext">密文：</label>
                    <textarea
                        id="normal-ciphertext"
                        v-model="normalCiphertext"
                        placeholder="请输入非 APP 参数密文..."
                        class="textarea-input"
                        rows="14"
                    ></textarea>
                </div>

                <div class="button-section">
                    <button
                        @click="handleNormalDecrypt"
                        :disabled="!normalCiphertext.trim() || isNormalDecrypting"
                        class="decrypt-btn"
                    >
                        {{ isNormalDecrypting ? '解密中...' : '解密' }}
                    </button>
                    <button
                        @click="handleNormalClear"
                        class="clear-btn"
                    >
                        清空
                    </button>
                </div>

                <div class="output-section">
                    <label for="normal-plaintext">明文：</label>
                    <textarea
                        id="normal-plaintext"
                        v-model="normalPlaintext"
                        placeholder="解密后的明文将显示在这里..."
                        class="textarea-output"
                        rows="14"
                        readonly
                    ></textarea>
                </div>

                <div v-if="normalErrorMessage" class="error-message">
                    {{ normalErrorMessage }}
                </div>
            </div>
        </div>
    </div>
</template>

<script>
import { AppRequestDecryptor } from '../utils/AppRequestDecryptor.js'
import { decryptApiPayload } from '../utils/ApiPayloadCrypto.js'

export default {
    name: 'DecryptTool',
    props: {
        msg: String
    },
    data() {
        return {
            appCiphertext: '',
            appPlaintext: '',
            isAppDecrypting: false,
            appErrorMessage: '',
            normalCiphertext: '',
            normalPlaintext: '',
            isNormalDecrypting: false,
            normalErrorMessage: ''
        }
    },
    methods: {
        handleAppDecrypt() {
            if (!this.appCiphertext.trim()) {
                this.appErrorMessage = '请输入密文'
                return
            }

            this.isAppDecrypting = true
            this.appErrorMessage = ''
            this.appPlaintext = ''

            setTimeout(() => {
                try {
                    const result = AppRequestDecryptor.decrypt(this.appCiphertext.trim())
                    const formattedResult = JSON.stringify(result, null, 2)
                    this.appPlaintext = formattedResult
                } catch (error) {
                    this.appErrorMessage = error.message || '解密失败，请检查密文格式是否正确'
                    this.appPlaintext = ''
                    console.error('解密错误:', error)
                } finally {
                    this.isAppDecrypting = false
                }
            }, 0)
        },
        handleAppClear() {
            this.appCiphertext = ''
            this.appPlaintext = ''
            this.appErrorMessage = ''
        },
        handleNormalDecrypt() {
            if (!this.normalCiphertext.trim()) {
                this.normalErrorMessage = '请输入密文'
                return
            }

            this.isNormalDecrypting = true
            this.normalErrorMessage = ''
            this.normalPlaintext = ''

            setTimeout(() => {
                try {
                    const result = this.decodeNormalParam(this.normalCiphertext.trim())
                    this.normalPlaintext = JSON.stringify(result, null, 2)
                } catch (error) {
                    this.normalErrorMessage = error.message || '解密失败，请检查密文格式是否正确'
                    this.normalPlaintext = ''
                    console.error('非APP解密错误:', error)
                } finally {
                    this.isNormalDecrypting = false
                }
            }, 0)
        },
        handleNormalClear() {
            this.normalCiphertext = ''
            this.normalPlaintext = ''
            this.normalErrorMessage = ''
        },
        decodeNormalParam(input) {
            return decryptApiPayload(input)
        }
    }
}
</script>

<style scoped>
.decrypt-container {
    max-width: 1800px;
    margin: 0 auto;
    padding: 16px;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif;
}

.header {
    text-align: center;
    margin-bottom: 30px;
}

.header h1 {
    color: #2c3e50;
    font-size: 28px;
    font-weight: 600;
    margin: 0;
}

.content {
    display: flex;
    flex-direction: column;
    gap: 20px;
}

.two-column {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 20px;
    align-items: start;
}

.decrypt-panel {
    padding: 18px;
    border: 1px solid #ebeef5;
    border-radius: 8px;
    background-color: #fff;
}

.decrypt-panel h2 {
    margin: 0 0 14px;
    font-size: 18px;
    color: #2c3e50;
}

.input-section,
.output-section {
    display: flex;
    flex-direction: column;
    gap: 8px;
}

label {
    font-weight: 500;
    color: #333;
    font-size: 14px;
    text-align: left;
}

.textarea-input,
.textarea-output {
    width: 100%;
    padding: 12px;
    border: 1px solid #ddd;
    border-radius: 6px;
    font-size: 14px;
    font-family: 'Courier New', monospace;
    resize: vertical;
    transition: border-color 0.3s, box-shadow 0.3s;
    box-sizing: border-box;
}

.textarea-input:focus {
    outline: none;
    border-color: #409eff;
    box-shadow: 0 0 0 2px rgba(64, 158, 255, 0.1);
}

.textarea-output {
    background-color: #f5f7fa;
    color: #606266;
}

.textarea-input::placeholder,
.textarea-output::placeholder {
    color: #c0c4cc;
}

.button-section {
    display: flex;
    gap: 12px;
    justify-content: center;
    margin-top: 15px;
}

.decrypt-btn,
.clear-btn {
    padding: 10px 24px;
    font-size: 14px;
    font-weight: 500;
    border: none;
    border-radius: 6px;
    cursor: pointer;
    transition: all 0.3s;
}

.decrypt-btn {
    background-color: #409eff;
    color: white;
    min-width: 100px;
}

.decrypt-btn:hover:not(:disabled) {
    background-color: #66b1ff;
}

.decrypt-btn:active:not(:disabled) {
    background-color: #3a8ee6;
}

.decrypt-btn:disabled {
    background-color: #c0c4cc;
    cursor: not-allowed;
    opacity: 0.6;
}

.clear-btn {
    background-color: #909399;
    color: white;
    min-width: 100px;
}

.clear-btn:hover {
    background-color: #a6a9ad;
}

.clear-btn:active {
    background-color: #82848a;
}

.error-message {
    padding: 12px;
    background-color: #fef0f0;
    border: 1px solid #fde2e2;
    border-radius: 6px;
    color: #f56c6c;
    font-size: 14px;
    text-align: center;
}

@media (max-width: 768px) {
    .decrypt-container {
        padding: 15px;
    }

    .two-column {
        grid-template-columns: 1fr;
    }
    
    .header h1 {
        font-size: 24px;
    }
    
    .button-section {
        flex-direction: column;
    }
    
    .decrypt-btn,
    .clear-btn {
        width: 100%;
    }
}
</style>